url5 &lt;- "https://en.wikipedia.org/wiki/Love_Island_USA_season_5"
url4 &lt;- "https://en.wikipedia.org/wiki/Love_Island_USA_season_4"
url3 &lt;- "https://en.wikipedia.org/wiki/Love_Island_USA_season_3"
url2 &lt;- "https://en.wikipedia.org/wiki/Love_Island_USA_season_2"
url1 &lt;- "https://en.wikipedia.org/wiki/Love_Island_USA_season_1"

extract_couples &lt;- function(url) {
page &lt;- read_html(url)
all_tables &lt;- page |&gt; html_elements("table.wikitable") # |&gt; html_table()
coupling_table &lt;- all_tables[[2]]

rows &lt;- coupling_table |&gt;
   html_element("tbody") |&gt;
   html_elements("tr")

rows &lt;- rows[-c(1, 2, length(rows)-c(0:6))]

names &lt;- rows |&gt;
   html_elements("th") |&gt;
   html_text() |&gt;
   str_trim()

extract_matches &lt;- function(row) {
   row |&gt;
     html_elements("td") |&gt;
     html_text() |&gt;
     str_trim()
 }

map(rows, extract_matches) |&gt;
  map2(names, ~ tibble(x = .y, y = .x)) |&gt;
  list_rbind() |&gt;
  filter(!str_detect(y, "\\(")) |&gt;
   filter(!str_detect(y, "\\)")) |&gt;
   filter(!str_detect(y, "\\&")) |&gt;
   filter(!str_detect(y, "save")) |&gt;
   filter(!str_detect(y, "dump")) |&gt;
   filter(!str_detect(y, "100")) |&gt;
   filter(y != "N/A", y != "Not in Villa", y != "Single", y != "Safe", y != "Saved", y != "Finalist", y != "Vulnerable", y != "Eliminated", y != "Not inVilla", y != "Immune")
}


li_data &lt;- paste0("https://en.wikipedia.org/wiki/Love_Island_USA_season_", 1:8) |&gt;
 map(extract_couples) |&gt;
 list_rbind(names_to = "season") |&gt;
 select(x, y, season)

write_csv(li_data,"data.csv")

Each node is a person on Love Island and Each line connects who was officaly coupled up at one point.

library(ggraph)
library(tidygraph)
library(igraph)

chart_graph &lt;- function(data) {
as_tbl_graph(data, directed = FALSE) |&gt;
 ggraph(layout = "fr") +
   geom_edge_link() +
   geom_node_point() +
   geom_node_text(aes(label = name), repel = TRUE) +
   theme_graph() +
   theme(
     plot.background = element_rect(fill = "transparent", color = NA),
     panel.background = element_rect(fill = "transparent", color = NA)
) 
}


